  .when(xpath("/oc:order_confirmation/oc:order/oc:customer/@category = '140'"))
    .to(DIRECT_CUSTOMER1)
  .when(xpath("/oc:order_confirmation/oc:order/oc:customer/@category = '116'"))
    .to(DIRECT_CUSTOMER2);
{code}

